//   namespace: istio-ingress
// spec:
//   selector:
//     matchLabels:
//       istio: ingressgateway
//   phase: AUTHN
//   wasm:
//     url: oci://private-registry:5000/openid-connect/openid:latest
//     imagePullPolicy: IfNotPresent
//     imagePullSecret: private-registry-pull-secret
//     pluginConfig:
//       openid_server: authn
//       openid_realm: ingress
// ```
